{
 "level": "A2–B1",
 "intro": "In this topic, you will learn <strong>indefinite pronouns</strong> - words to indicate indefinite people, things and places.",
 "rules": [
 {
 "label": "SOME-",
 "color": "emerald",
 "text": "<strong>Some-</strong> in statements:",
 "example": "Someone called. Something happened."
 },
 {
 "label": "ANY-",
 "color": "blue",
 "text": "<strong>Any-</strong> in questions and negatives:",
 "example": "Did anyone see it? I didn't see anything."
 },
 {
 "label": "NO-",
 "color": "rose",
 "text": "<strong>No-</strong> for negation:",
 "example": "Nobody knows. Nothing is wrong."
 }
 ]
}

{
 "title": "1. Four groups of indefinite pronouns",
 "intro": "Indefinite pronouns are divided into four main groups:",
 "items": [
 {
 "label": "SOME-",
 "title": "Someone, something",
 "subtitle": "someone/somebody, something, somewhere — in in statements"
 },
 {
 "label": "ANY-",
 "title": "Anyone, anything",
 "subtitle": "anyone/anybody, anything, anywhere - in questions and negatives"
 },
 {
 "label": "NO-",
 "title": "No one, nothing",
 "subtitle": "no one/nobody, nothing, nowhere - for negation"
 },
 {
 "label": "EVERY-",
 "title": "Everybody, everything",
 "subtitle": "everyone/everybody, everything, everywhere - everyone without exception"
 }
 ]
}

{
 "title": "2. Complete table of indefinite pronouns",
 "intro": "Three categories: people (-one/-body), things (-thing), places (-where):",
 "rows": [
 {
 "en": "SOME-",
 "ua": "SOME-",
 "note": "someone/somebody, something, somewhere"
 },
 {
 "en": "ANY-",
 "ua": "ANY-",
 "note": "anyone/anybody, anything, anywhere"
 },
 {
 "en": "NO-",
 "ua": "NO-",
 "note": "no one/nobody, nothing, nowhere"
 },
 {
 "en": "EVERY-",
 "ua": "EVERY-",
 "note": "everyone/everybody, everything, everywhere"
 }
 ],
 "warning": "📌 -one/-body (people), -thing (things), -where (places)."
}

{
 "title": "3. SOME- (somebody, something, somewhere) door.",
 "sections": [
 {
 "label": "Key point",
 "color": "emerald",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "Someone is at the door.",
 "ua": "Someone is at the door."
 },
 {
 "en": "I saw somebody in the garden.",
 "ua": "I saw somebody in the garden."
 },
 {
 "en": "Something is wrong.",
 "ua": "Something is wrong."
 },
 {
 "en": "I left my keys somewhere.",
 "ua": "I left my keys somewhere."
 }
 ]
 },
 {
 "label": "In questions (suggestions)",
 "color": "sky",
 "description": "Some- is also used in <strong>questions-suggestions</strong> or when we expect an affirmative answer.",
 "examples": [
 {
 "en": "Would you like something to drink?",
 "ua": "Would you like something to drink?"
 },
 {
 "en": "Can someone help I?",
 "ua": "Can someone help I?"
 },
 {
 "en": "Did you go somewhere nice?",
 "ua": "Did you go somewhere nice?"
 }
 ],
 "note": "Use the pattern in the examples and focus on the highlighted words."
 },
 {
 "label": "Someone vs Somebody",
 "color": "purple",
 "description": "<strong>Someone</strong> and <strong>somebody</strong> are synonyms. Same with something.",
 "examples": [
 {
 "en": "Someone called = Somebody called",
 "ua": "Someone called = Somebody called"
 },
 {
 "en": "I heard something = I heard a noise",
 "ua": "I heard something = I heard a noise"
 }
 ],
 "note": "Someone/something"
 }
 ]
}

{
 "title": "4. ANY-: anyone, anything, anywhere",
 "sections": [
 {
 "label": "In questions",
 "color": "blue",
 "description": "Use <strong>any-</strong> words in neutral questions about people, things or places.",
 "examples": [
 {
 "en": "Did anyone call?",
 "ua": "Did anyone call?"
 },
 {
 "en": "Is anybody home?",
 "ua": "Is anybody home?"
 },
 {
 "en": "Did you see anything?",
 "ua": "Did you see anything?"
 },
 {
 "en": "Are you going anywhere?",
 "ua": "Are you going anywhere?"
 }
 ]
 },
 {
 "label": "In negatives",
 "color": "sky",
 "description": "Use <strong>any-</strong> after a negative verb with <em>not</em>.",
 "examples": [
 {
 "en": "I didn't see anyone.",
 "ua": "I didn't see anyone."
 },
 {
 "en": "She doesn't know anybody.",
 "ua": "She doesn't know anybody."
 },
 {
 "en": "I didn't buy anything.",
 "ua": "I didn't buy anything."
 },
 {
 "en": "We didn't go anywhere.",
 "ua": "We didn't go anywhere."
 }
 ],
 "note": "Not + any- is a common alternative to a no- word."
 },
 {
 "label": "In open statements",
 "color": "purple",
 "description": "In statements, <strong>any-</strong> can mean no matter who, what or where.",
 "examples": [
 {
 "en": "Anyone can do it.",
 "ua": "Anyone can do it."
 },
 {
 "en": "You can take anything you want.",
 "ua": "You can take anything you want."
 },
 {
 "en": "We can go anywhere.",
 "ua": "We can go anywhere."
 }
 ],
 "note": "Any- in statements often means without restriction."
 }
 ]
}

{
 "title": "5. NO- (nobody, nothing, nowhere)",
 "sections": [
 {
 "label": "For negation",
 "color": "rose",
 "description": "Pronouns with <strong>no-</strong> create <strong>negation</strong> themselves. Don't need not!",
 "examples": [
 {
 "en": "Nobody knows the answer.",
 "ua": "Nobody knows the answer."
 },
 {
 "en": "No one came to the party.",
 "ua": "No one came to the party."
 },
 {
 "en": "Nothing is impossible.",
 "ua": "Nothing is impossible."
 },
 {
 "en": "I've been nowhere interesting.",
 "ua": "I've been nowhere interesting."
 }
 ],
 "note": "📌 NO- already a denial! Do not add not!"
 },
 {
 "label": "Nobody = Not anybody",
 "color": "amber",
 "description": "No- and not + any- are synonyms. Both options are correct.",
 "examples": [
 {
 "en": "Nobody called = No one called",
 "ua": "Nobody called = No one called"
 },
 {
 "en": "I didn't see anyone = I saw nobody",
 "ua": "I didn't see anyone = I saw nobody"
 },
 {
 "en": "She didn't say anything = She said nothing",
 "ua": "She didn't say anything = She said nothing"
 }
 ],
 "note": "No- a little more formal and categorical."
 },
 {
 "label": "Error: double negation!",
 "color": "red",
 "description": "In English you can NOT use double negation!",
 "examples": [
 {
 "en": "I didn't see nobody. (✗)",
 "ua": "I didn't see nobody. (✗)"
 },
 {
 "en": "I didn't see anyone. (✓)",
 "ua": "I didn't see anyone. (✓)"
 },
 {
 "en": "I saw nobody. (✓)",
 "ua": "I saw nobody. (✓)"
 }
 ],
 "note": "📌 Not + no- = ERROR! Choose one: not + any- OR no-."
 }
 ]
}

{
 "title": "6. EVERY- (everyone, everything, everywhere)",
 "sections": [
 {
 "label": "All without exception",
 "color": "purple",
 "description": "Pronouns with <strong>every-</strong> mean <strong>everyone without exception</strong>.",
 "examples": [
 {
 "en": "Everyone is here.",
 "ua": "Everyone is here."
 },
 {
 "en": "Everybody Knows that. singular!",
 "ua": "Everybody Knows that. singular!"
 },
 {
 "en": "Everything is fine.",
 "ua": "Everything is fine."
 },
 {
 "en": "I've looked everywhere.",
 "ua": "I've looked everywhere."
 }
 ]
 },
 {
 "label": "Key point",
 "color": "amber",
 "description": "Everyone/everybody is <strong>singular</strong>! The verb is in the singular form.",
 "examples": [
 {
 "en": "Everyone is ready. (✓)",
 "ua": "Everyone is ready. (✓)"
 },
 {
 "en": "Everyone is ready. (✗)",
 "ua": "Everyone is ready. (✗)"
 },
 {
 "en": "Everybody has a ticket.",
 "ua": "Everybody has a ticket."
 }
 ],
 "note": "📌 Everyone/everybody = singular (is, has, does)."
 },
 {
 "label": "Everyone vs Everybody",
 "color": "sky",
 "description": "<strong>Everyone</strong> and <strong>everybody</strong> are synonyms.",
 "examples": {
 "en": "Everyone is welcome = Everybody is welcome",
 "ua": "Everyone is welcome = Everybody is welcome"
 },
 "note": "Everybody is a little more formal. Everybody is conversational."
 }
 ]
}

{
 "title": "7. Grammatical rules",
 "sections": [
 {
 "label": "Singular or plural?",
 "color": "emerald",
 "description": "All indefinite pronouns are grammatically <strong>singular</strong>, even everyone/everybody.",
 "examples": [
 {
 "en": "Someone is calling. (✓)",
 "ua": "Someone is calling. (✓)"
 },
 {
 "en": "Nobody knows. (✓)",
 "ua": "Nobody knows. (✓)"
 },
 {
 "en": "Everyone has arrived. (✓)",
 "ua": "Everyone has arrived. (✓)"
 }
 ],
 "note": "📌 Is, has, does (not are, have, do). something (✗)"
 },
 {
 "label": "Key point",
 "color": "blue",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "something interesting (✓)",
 "ua": "something interesting (✓)"
 },
 {
 "en": "interesting something (✗)",
 "ua": "interesting something (✗)"
 },
 {
 "en": "someone special",
 "ua": "someone special"
 },
 {
 "en": "nothing important",
 "ua": "nothing important"
 }
 ],
 "note": "📌 Indefinite pronoun + adjective (after, not before)."
 },
 {
 "label": "Pronouns for return",
 "color": "purple",
 "description": "To return to everyone/somebody, we use they/their (although grammatically singular).",
 "examples": [
 {
 "en": "Someone left their bag. (✓)",
 "ua": "Someone left their bag. (✓)"
 },
 {
 "en": "Everyone should do their homework.",
 "ua": "Everyone should do their homework."
 }
 ],
 "note": "📌 We use they/their for neutrality (not he/his)."
 }
 ]
}

{
 "title": "8. Common mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Double negation (not + no-).",
 "wrong": "I didn't see nobody. / She didn't say nothing.",
 "right": "​​​​ <span class=\"font-mono\">I didn't see anyone. / She said nothing.</span>"
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Plural verb with everyone.",
 "wrong": "Everyone are here. / Everybody has tickets.",
 "right": " ✅ <span class=\"font-mono\">Everyone is here. / Everybody has tickets.</span>"
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "Adjective before pronoun.",
 "wrong": "I want interesting something. / He met someone special.",
 "right": " ✅ <span class=\"font-mono\">I want something interesting. / He met someone special.</span>"
 },
 {
 "label": "Error 4",
 "color": "purple",
 "title": "Some- in questions (when not a proposition).",
 "wrong": "Did someone call? (general question)",
 "right": " ✅ <span class=\"font-mono\">Did anyone call?</span> (general) / <span class=\"font-mono\">Did someone help you?</span> (we expect \"yes\")"
 }
 ]
}

{
 "title": "10. Practice",
 "select_title": "Exercise 1. Choose the correct pronoun",
 "select_intro": "Fill in the blanks with the correct indefinite pronoun.",
 "selects": [
 {
 "label": "___ is at the door. (Someone / Anyone)",
 "prompt": "What pronoun?"
 },
 {
 "label": "Did ___ call? (someone / anyone)",
 "prompt": "What pronoun?"
 },
 {
 "label": "___ knows the answer. (Nobody / Anybody)",
 "prompt": "What pronoun?"
 },
 {
 "label": "___ is ready. (Everyone / Anyone)",
 "prompt": "Which pronoun?"
 },
 {
 "label": "I didn't see ___. (anyone / someone)",
 "prompt": "What pronoun?"
 }
 ],
 "options": [
 "someone",
 "anyone",
 "nobody",
 "everyone",
 "something",
 "anything",
 "nothing",
 "everything"
 ],
 "input_title": "Exercise 2. Fill in the blanks",
 "input_intro": "Write the correct indefinite pronoun.",
 "inputs": [
 {
 "before": "___ called me. (someone called)",
 "after": "→"
 },
 {
 "before": "Did you see ___? (saw something)",
 "after": "→"
 },
 {
 "before": "___ came to the party. (no one came)",
 "after": "→"
 },
 {
 "before": "___ is possible! (everything is possible)",
 "after": "→"
 }
 ],
 "rephrase_title": "Exercise 3. Error correction",
 "rephrase_intro": "Find and correct the error with indefinite pronouns.",
 "rephrase": [
 {
 "example_label": "Example:",
 "example_original": "I didn't see nobody.",
 "example_target": "I didn't see anyone."
 },
 {
 "original": "1. Everyone is ready.",
 "placeholder": "Fix the error"
 },
 {
 "original": "2. I want interesting something.",
 "placeholder": "Fix the error"
 },
 {
 "original": "3. She didn't say nothing.",
 "placeholder": "Correct an error"
 }
 ]
}

{
 "title": "Keep learning",
 "items": [
 {
 "label": "Pronouns - Pronouns (overview)",
 "current": false
 },
 {
 "label": "Personal & Object Pronouns - Personal and object",
 "current": false
 },
 {
 "label": "Possessive Adjectives vs Pronouns — my / mine",
 "current": false
 },
 {
 "label": "Indefinite Pronouns — someone, anyone, nobody, nothing",
 "current": true
 }
 ]
}
